150	
151	    let log_dir = project_config
152	        .project
153	        .log_dir
154	        .as_ref()
155	        .map(|d| base_dir.join(d));
156	
157	    let mut manager = SessionManager::new(log_dir);
158	
159	    // Build agent configs and spawn sessions.
160	    let mut agent_configs_map: HashMap<String, AgentConfig> = HashMap::new();
161	    for entry in &project_config.agents {
162	        let config = entry.to_agent_config(&base_dir);
163	        agent_configs_map.insert(entry.id.clone(), config.clone());
164	        match manager.spawn_agent(config) {
165	            Ok(id) => tracing::info!("Spawned agent: {id} ({})", entry.name),
