170	    let agent_ids: Vec<String> = manager.agent_ids().iter().map(|id| id.0.clone()).collect();
171	
172	    // Build repo_path map for saga lookups.
173	    let agent_repo_paths: HashMap<String, PathBuf> = agent_configs_map
