183	    // Initialize wiki storage and seed coordination pages.
184	    let wiki_dir = base_dir.join(".atn").join("wiki");
185	    let wiki = Arc::new(FileWikiStorage::new(&wiki_dir));
186	    let now = wiki_common::time::now();
187	    atn_wiki::coordination::seed_coordination_pages(wiki.as_ref(), now).await;
