261	/// Wait for SIGINT (Ctrl-C) or SIGTERM.
262	async fn shutdown_signal() {
263	    let ctrl_c = async {
264	        tokio::signal::ctrl_c()
265	            .await
266	            .expect("failed to install Ctrl-C handler");
267	    };
268	
269	    #[cfg(unix)]
270	    let terminate = async {
271	        tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate())
272	            .expect("failed to install SIGTERM handler")
273	            .recv()
274	            .await;
275	    };
276	
277	    #[cfg(not(unix))]
278	    let terminate = std::future::pending::<()>();
279	
280	    tokio::select! {
281	        () = ctrl_c => tracing::info!("Received Ctrl-C, starting graceful shutdown"),
282	        () = terminate => tracing::info!("Received SIGTERM, starting graceful shutdown"),
283	    }
284	}
