290	/// Returns full agent info with state for all agents.
291	async fn list_agents(State(state): State<AppState>) -> Json<Vec<AgentInfo>> {
292	    let pending: Vec<_> = {
293	        let mgr = state.manager.lock().await;
294	        mgr.agent_ids()
295	            .iter()
296	            .filter_map(|id| {
297	                mgr.get_session(id).ok().map(|session| {
298	                    (
299	                        id.0.clone(),
300	                        session.name().to_string(),
301	                        session.role().to_string(),
302	                        session.state(),
303	                    )
304	                })
305	            })
306	            .collect()
307	    };
308	    let mut agents = Vec::with_capacity(pending.len());
309	    for (id, name, role, state_lock) in pending {
310	        let s = state_lock.read().await;
311	        agents.push(AgentInfo {
312	            id,
313	            name,
314	            role,
315	            state: s.clone(),
316	        });
317	    }
318	    Json(agents)
319	}
