321	/// Returns current state for a single agent.
322	async fn agent_state(
323	    Path(id): Path<String>,
324	    State(state): State<AppState>,
325	) -> Result<Json<AgentInfo>, StatusCode> {
326	    let agent_id = AgentId(id);
327	    let (name, role, state_lock) = {
328	        let mgr = state.manager.lock().await;
329	        let session = mgr
330	            .get_session(&agent_id)
331	            .map_err(|_| StatusCode::NOT_FOUND)?;
332	        (
333	            session.name().to_string(),
334	            session.role().to_string(),
335	            session.state(),
336	        )
