347	async fn agent_sse(
348	    Path(id): Path<String>,
349	    State(state): State<AppState>,
350	) -> Result<Sse<impl futures_core::Stream<Item = Result<Event, Infallible>>>, StatusCode> {
351	    let agent_id = AgentId(id);
352	    let mgr = state.manager.lock().await;
353	    let session = mgr
354	        .get_session(&agent_id)
355	        .map_err(|_| StatusCode::NOT_FOUND)?;
356	    let rx = session.output_receiver();
357	    drop(mgr);
358	
359	    let stream =
360	        tokio_stream::wrappers::BroadcastStream::new(rx).filter_map(|result| match result {
361	            Ok(OutputSignal::Bytes(bytes)) => {
362	                let b64 = base64::engine::general_purpose::STANDARD.encode(&bytes);
363	                Some(Ok(Event::default().data(b64)))
364	            }
365	            _ => None,
366	        });
367	
368	    Ok(Sse::new(stream).keep_alive(KeepAlive::default()))
369	}
