379	        let session = mgr
380	            .get_session(&agent_id)
381	            .map_err(|_| StatusCode::NOT_FOUND)?;
382	        session.input_sender()
383	    };
384	    tx.send(InputEvent::HumanText {
385	        text: payload.text,
386	    })
387	    .await
388	    .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
389	    Ok(StatusCode::OK)
390	}
