414	/// Restart an agent session: shut down if running, then re-spawn from stored config.
415	async fn agent_restart(
416	    Path(id): Path<String>,
417	    State(state): State<AppState>,
418	) -> Result<StatusCode, StatusCode> {
419	    let agent_id = AgentId(id.clone());
420	
421	    // Get the config for this agent.
422	    let config = {
423	        let configs = state.agent_configs.lock().await;
424	        configs.get(&id).cloned().ok_or(StatusCode::NOT_FOUND)?
425	    };
426	
427	    // Remove the existing session (if any) without holding the lock across await.
428	    let old_session = {
429	        let mut mgr = state.manager.lock().await;
430	        mgr.remove_agent(&agent_id).ok()
431	    };
432	    if let Some(mut session) = old_session {
433	        let _ = session.shutdown().await;
434	    }
435	
436	    // Re-spawn from stored config.
437	    {
438	        let mut mgr = state.manager.lock().await;
439	        mgr.spawn_agent(config)
440	            .map_err(|e| {
441	                tracing::error!("Failed to restart agent '{id}': {e}");
442	                StatusCode::INTERNAL_SERVER_ERROR
443	            })?;
444	    }
445	
446	    tracing::info!("Restarted agent: {id}");
447	    Ok(StatusCode::OK)
448	}
