450	/// Dependency graph: which agents are blocked and by what.
451	#[derive(Serialize)]
452	struct DepGraphNode {
453	    id: String,
454	    name: String,
455	    state: String,
456	    blocked_on: Vec<String>,
457	}
458	
459	async fn agent_dependency_graph(
460	    State(state): State<AppState>,
461	) -> Json<Vec<DepGraphNode>> {
462	    let pending: Vec<_> = {
463	        let mgr = state.manager.lock().await;
464	        mgr.agent_ids()
465	            .iter()
466	            .filter_map(|id| {
467	                mgr.get_session(id).ok().map(|session| {
468	                    (
469	                        id.0.clone(),
470	                        session.name().to_string(),
471	                        session.state(),
472	                    )
473	                })
474	            })
475	            .collect()
476	    };
477	
478	    let mut nodes = Vec::with_capacity(pending.len());
479	    for (id, name, state_lock) in pending {
480	        let s = state_lock.read().await;
481	        let blocked_on = match &*s {
482	            AgentState::Blocked { on } => on.clone(),
483	            _ => vec![],
484	        };
485	        let state_key = serde_json::to_value(&*s)
486	            .ok()
487	            .and_then(|v| v.get("state").and_then(|s| s.as_str()).map(String::from))
488	            .unwrap_or_else(|| "unknown".to_string());
489	        nodes.push(DepGraphNode {
490	            id,
491	            name,
492	            state: state_key,
493	            blocked_on,
494	        });
495	    }
496	
497	    Json(nodes)
498	}
