500	/// Watch agents.toml for changes and hot-reload agent configuration.
501	fn spawn_config_watcher(config_path: PathBuf, base_dir: PathBuf, state: SharedState) {
502	    use notify::{EventKind, RecursiveMode, Watcher};
503	
504	    let (tx, mut rx) = tokio::sync::mpsc::channel(16);
505	
506	    // Spawn the blocking file watcher in a dedicated thread.
507	    std::thread::spawn(move || {
508	        let tx = tx;
509	        let mut watcher = match notify::recommended_watcher(
510	            move |res: Result<notify::Event, notify::Error>| {
511	                if let Ok(event) = res
512	                    && matches!(event.kind, EventKind::Modify(_) | EventKind::Create(_))
513	                {
514	                    let _ = tx.blocking_send(());
515	                }
516	            },
517	        ) {
518	            Ok(w) => w,
519	            Err(e) => {
520	                tracing::error!("Failed to create config file watcher: {e}");
521	                return;
522	            }
523	        };
524	        if let Err(e) = watcher.watch(&config_path, RecursiveMode::NonRecursive) {
525	            tracing::error!("Failed to watch {}: {e}", config_path.display());
526	            return;
527	        }
528	        tracing::info!("Watching {} for changes", config_path.display());
529	        // Keep watcher alive.
530	        loop {
531	            std::thread::sleep(std::time::Duration::from_secs(3600));
532	        }
533	    });
534	
535	    // Process reload signals on the async runtime.
536	    // We use LocalSet-free approach: collect decisions without holding manager lock,
537	    // then apply them.
538	    let manager = state.manager.clone();
539	    let agent_configs = state.agent_configs.clone();
540	    let agent_repo_paths = state.agent_repo_paths.clone();
541	
542	    tokio::spawn(async move {
543	        // Debounce: wait 500ms after last event before reloading.
544	        while rx.recv().await.is_some() {
545	            tokio::time::sleep(std::time::Duration::from_millis(500)).await;
546	            while rx.try_recv().is_ok() {}
547	
548	            let config_path_for_load = base_dir.join(DEFAULT_CONFIG_PATH);
549	            tracing::info!("Config file changed, reloading...");
550	
551	            let new_config = match load_project_config(&config_path_for_load) {
552	                Ok(c) => c,
553	                Err(e) => {
554	                    tracing::error!("Failed to reload config: {e}");
555	                    continue;
556	                }
557	            };
558	
559	            let new_ids: std::collections::HashSet<String> =
560	                new_config.agents.iter().map(|a| a.id.clone()).collect();
561	            let current_ids: std::collections::HashSet<String> = {
562	                let mgr = manager.lock().await;
563	                mgr.agent_ids().iter().map(|id| id.0.clone()).collect()
564	            };
565	
566	            // Remove agents no longer in config.
567	            let to_remove: Vec<String> = current_ids.difference(&new_ids).cloned().collect();
568	            for id in &to_remove {
569	                let agent_id = AgentId(id.clone());
570	                let old_session = {
571	                    let mut mgr = manager.lock().await;
572	                    mgr.remove_agent(&agent_id).ok()
573	                };
574	                if let Some(mut session) = old_session {
575	                    if let Err(e) = session.shutdown().await {
576	                        tracing::warn!("Hot-reload: error shutting down agent '{id}': {e}");
577	                    }
578	                    tracing::info!("Hot-reload: removed agent '{id}'");
579	                }
580	            }
581	
582	            // Add new agents or update configs.
583	            let to_add: Vec<_> = new_config
584	                .agents
585	                .iter()
586	                .filter(|entry| !current_ids.contains(&entry.id))
587	                .cloned()
588	                .collect();
589	
590	            // Update all configs and repo paths.
591	            {
592	                let mut configs = agent_configs.lock().await;
593	                let mut repo_paths = agent_repo_paths.lock().await;
594	                for entry in &new_config.agents {
595	                    let config = entry.to_agent_config(&base_dir);
596	                    repo_paths.insert(entry.id.clone(), config.repo_path.clone());
597	                    configs.insert(entry.id.clone(), config);
598	                }
599	            }
600	
601	            // Spawn newly added agents.
602	            // Each spawn_agent call is done in a scope that drops the lock before the next.
603	            for entry in &to_add {
604	                let config = entry.to_agent_config(&base_dir);
605	                let id = entry.id.clone();
606	                let result = manager.lock().await.spawn_agent(config);
607	                match result {
608	                    Ok(_) => tracing::info!("Hot-reload: added agent '{id}'"),
609	                    Err(e) => {
610	                        tracing::error!("Hot-reload: failed to spawn agent '{id}': {e}");
611	                    }
612	                }
613	            }
614	        }
615	    });
616	}
