620	/// Build a SagaResponse from a repo path (blocking I/O in spawn_blocking).
621	async fn saga_for_path(repo_path: PathBuf) -> SagaResponse {
622	    tokio::task::spawn_blocking(move || {
623	        let saga = atn_trail::reader::load_saga(&repo_path)
624	            .ok()
625	            .flatten();
626	        let steps = atn_trail::reader::list_steps(&repo_path).unwrap_or_default();
627	        let task_type = steps
628	            .iter()
629	            .find(|s| s.status == "in-progress")
630	            .and_then(|s| s.task_type.as_deref())
631	            .unwrap_or("");
632	        let trajectories = if task_type.is_empty() {
633	            vec![]
634	        } else {
635	            atn_trail::reader::load_trajectories(&repo_path, task_type)
636	                .unwrap_or_default()
637	        };
638	        SagaResponse {
639	            saga,
640	            steps,
641	            trajectories,
642	        }
643	    })
644	    .await
645	    .unwrap_or_else(|_| SagaResponse {
646	        saga: None,
647	        steps: vec![],
648	        trajectories: vec![],
649	    })
650	}
651	
652	/// Get saga info for the project (uses cwd).
653	async fn get_project_saga() -> Json<SagaResponse> {
654	    let cwd = std::env::current_dir().unwrap_or_default();
