694	/// Get a wiki page by title. Returns JSON with ETag header.
695	async fn wiki_get_page(
696	    Path(title): Path<String>,
697	    State(state): State<AppState>,
698	) -> Result<Response, StatusCode> {
699	    let page = state
700	        .wiki
701	        .get_page(&title)
702	        .await
703	        .ok_or(StatusCode::NOT_FOUND)?;
704	
705	    let etag = content_etag(&page.content);
706	    let html = render_wiki_content(&page.content);
707	    let body = WikiPageResponse {
708	        title: page.title,
709	        content: page.content,
710	        html,
711	        created_at: page.created_at,
712	        updated_at: page.updated_at,
713	    };
714	
715	    let mut response = Json(body).into_response();
716	    response
717	        .headers_mut()
718	        .insert("ETag", etag.parse().unwrap());
719	    Ok(response)
720	}
721	
722	/// Create or update a wiki page. Requires If-Match header for existing pages.
723	async fn wiki_put_page(
724	    Path(title): Path<String>,
725	    headers: HeaderMap,
726	    State(state): State<AppState>,
727	    Json(body): Json<WikiPutBody>,
728	) -> Result<Response, Response> {
729	    let existing = state.wiki.get_page(&title).await;
730	    let now = wiki_common::time::now();
731	    let is_update = existing.is_some();
732	    let prev_created_at = existing.as_ref().map(|p| p.created_at);
733	
734	    if let Some(ref page) = existing {
735	        let current_etag = content_etag(&page.content);
736	        let if_match = headers
737	            .get("If-Match")
738	            .and_then(|v| v.to_str().ok())
739	            .map(|s| s.to_string());
740	
741	        match if_match {
742	            None => {
743	                return Err(conflict_response(page, &current_etag));
744	            }
745	            Some(provided) if provided != current_etag => {
746	                return Err(conflict_response(page, &current_etag));
747	            }
748	            _ => {}
749	        }
750	    }
751	
752	    let created_at = prev_created_at.unwrap_or(now);
753	    let page = WikiPage {
754	        title: title.clone(),
755	        content: body.content.clone(),
756	        created_at,
757	        updated_at: now,
758	    };
759	    state.wiki.save_page(page).await;
760	
761	    let etag = content_etag(&body.content);
762	    let html = render_wiki_content(&body.content);
763	    let resp = WikiPageResponse {
764	        title,
765	        content: body.content,
766	        html,
767	        created_at,
768	        updated_at: now,
769	    };
770	
771	    let mut response = Json(resp).into_response();
772	    response
773	        .headers_mut()
774	        .insert("ETag", etag.parse().unwrap());
775	    *response.status_mut() = if is_update {
776	        StatusCode::OK
777	    } else {
778	        StatusCode::CREATED
779	    };
780	    Ok(response)
781	}
782	
783	/// Patch a wiki page using structured operations. Requires If-Match or etag in body.
784	async fn wiki_patch_page(
785	    Path(title): Path<String>,
786	    State(state): State<AppState>,
787	    Json(patch): Json<PatchRequest>,
788	) -> Result<Response, Response> {
789	    let page = state
790	        .wiki
791	        .get_page(&title)
792	        .await
793	        .ok_or_else(|| StatusCode::NOT_FOUND.into_response())?;
794	
795	    let current_etag = content_etag(&page.content);
796	    if patch.etag != current_etag {
797	        return Err(conflict_response(&page, &current_etag));
798	    }
799	
800	    let new_content = apply_ops(&page.content, &patch.ops).map_err(|e| {
801	        (
802	            StatusCode::UNPROCESSABLE_ENTITY,
803	            Json(serde_json::json!({ "error": "patch failed", "op_index": e.op_index, "match_str": e.match_str })),
804	        )
805	            .into_response()
806	    })?;
807	
808	    let now = wiki_common::time::now();
809	    let updated = WikiPage {
810	        title: title.clone(),
811	        content: new_content.clone(),
812	        created_at: page.created_at,
813	        updated_at: now,
814	    };
815	    state.wiki.save_page(updated).await;
816	
817	    let etag = content_etag(&new_content);
818	    let html = render_wiki_content(&new_content);
819	    let resp = WikiPageResponse {
820	        title,
821	        content: new_content,
822	        html,
823	        created_at: page.created_at,
824	        updated_at: now,
825	    };
826	
827	    let mut response = Json(resp).into_response();
828	    response
829	        .headers_mut()
830	        .insert("ETag", etag.parse().unwrap());
831	    Ok(response)
832	}
833	
834	/// Delete a wiki page. Requires If-Match header.
835	async fn wiki_delete_page(
836	    Path(title): Path<String>,
837	    headers: HeaderMap,
838	    State(state): State<AppState>,
839	) -> Result<StatusCode, Response> {
840	    let page = state
841	        .wiki
842	        .get_page(&title)
843	        .await
844	        .ok_or(StatusCode::NOT_FOUND.into_response())?;
845	
846	    let current_etag = content_etag(&page.content);
847	    let if_match = headers
848	        .get("If-Match")
849	        .and_then(|v| v.to_str().ok())
850	        .map(|s| s.to_string());
851	
852	    match if_match {
853	        None => return Err(conflict_response(&page, &current_etag)),
854	        Some(provided) if provided != current_etag => {
855	            return Err(conflict_response(&page, &current_etag));
856	        }
857	        _ => {}
858	    }
859	
860	    state.wiki.delete_page(&title).await;
