862	}
863	
864	/// Build a 409 Conflict response with current page state.
865	fn conflict_response(page: &WikiPage, current_etag: &str) -> Response {
866	    let body = WikiConflictResponse {
867	        error: "ETag mismatch — page was modified".to_string(),
868	        current_etag: current_etag.to_string(),
869	        page: WikiPageResponse {
870	            title: page.title.clone(),
871	            content: page.content.clone(),
872	            html: render_wiki_content(&page.content),
873	            created_at: page.created_at,
874	            updated_at: page.updated_at,
875	        },
876	    };
877	    let mut resp = Json(body).into_response();
878	    *resp.status_mut() = StatusCode::CONFLICT;
879	    resp.headers_mut()
880	        .insert("ETag", current_etag.parse().unwrap());
881	    resp
882	}
883	
884	// ── Event log handlers ─────────────────────────────────────────────────
885	
886	/// List event log entries. Optional `?since=N` returns entries after index N.
887	async fn list_events(
888	    Query(query): Query<EventLogQuery>,
889	    State(state): State<AppState>,
890	) -> Json<Vec<EventLogEntry>> {
891	    let log = state.event_log.lock().await;
892	    let since = query.since.unwrap_or(0);
893	    Json(log.iter().skip(since).cloned().collect())
894	}
895	
896	/// Submit a push event for routing (e.g., from the UI or an external tool).
897	async fn submit_event(
898	    State(_state): State<AppState>,
899	    Json(body): Json<SubmitEventBody>,
900	) -> StatusCode {
901	    let event = body.event;
902	
903	    // Write the event to the source agent's outbox as a JSON file.
904	    let outbox_dir = PathBuf::from(".atn")
905	        .join("outboxes")
906	        .join(&event.source_agent);
907	    let _ = tokio::fs::create_dir_all(&outbox_dir).await;
908	    let file_path = outbox_dir.join(format!("{}.json", event.id));
909	    if let Ok(json) = serde_json::to_string_pretty(&event) {
910	        let _ = tokio::fs::write(&file_path, json).await;
911	    }
912	
913	    // The background router will pick it up on next poll.
914	    StatusCode::ACCEPTED
915	}
