244	        const STATE_LABELS = {
245	            starting: 'Starting',
246	            running: 'Running',
247	            idle: 'Idle',
248	            awaiting_human_input: 'Awaiting Input',
249	            busy: 'Busy',
250	            blocked: 'Blocked',
251	            completed_task: 'Completed',
252	            error: 'Error',
253	            disconnected: 'Disconnected',
254	        };
