256	        function stateKey(stateObj) {
257	            if (typeof stateObj === 'string') return stateObj;
258	            if (stateObj && stateObj.state) return stateObj.state;
259	            return 'starting';
260	        }
261	
262	        function stateLabel(stateObj) {
263	            const key = stateKey(stateObj);
264	            return STATE_LABELS[key] || key;
