267	        function createAgentPanel(agent) {
268	            const panel = document.createElement('div');
269	            panel.className = 'agent-panel';
270	            panel.id = `panel-${agent.id}`;
271	
272	            const sk = stateKey(agent.state);
273	
274	            panel.innerHTML = `
275	                <div class="agent-header">
