279	                    <span class="spacer"></span>
280	                    <span class="conn-dot disconnected" id="conn-${agent.id}"></span>
281	                    <span class="state-badge state-${sk}" id="badge-${agent.id}">${stateLabel(agent.state)}</span>
282	                </div>
283	                <div class="agent-terminal" id="term-${agent.id}"></div>
284	                <div class="agent-controls">
285	                    <input type="text" id="input-${agent.id}" placeholder="Command for ${agent.name}...">
286	                    <button class="btn-send" data-agent="${agent.id}">Send</button>
287	                    <button class="btn-ctrl-c" data-agent="${agent.id}">^C</button>
288	                    <button class="btn-restart" data-agent="${agent.id}">Restart</button>
289	                </div>
290	            `;
291	            return panel;
292	        }
