294	        function initTerminal(agentId) {
295	            const term = new Terminal({
296	                cursorBlink: true,
297	                fontSize: 13,
298	                fontFamily: "'JetBrains Mono', 'Fira Code', 'Cascadia Code', monospace",
299	                theme: {
300	                    background: '#0d1117',
301	                    foreground: '#c9d1d9',
302	                    cursor: '#e94560',
303	                    selectionBackground: '#264f78',
304	                },
