315	        function connectSSE(agentId) {
316	            const connDot = document.getElementById(`conn-${agentId}`);
317	            const evtSource = new EventSource(`${API_BASE}/api/agents/${agentId}/sse`);
318	            const agent = agents.get(agentId);
319	
320	            evtSource.onopen = () => {
321	                connDot.className = 'conn-dot connected';
322	            };
323	
324	            evtSource.onmessage = (event) => {
325	                const bytes = Uint8Array.from(atob(event.data), c => c.charCodeAt(0));
326	                agent.term.write(bytes);
327	            };
328	
329	            evtSource.onerror = () => {
330	                connDot.className = 'conn-dot disconnected';
331	                evtSource.close();
332	                setTimeout(() => connectSSE(agentId), 2000);
333	            };
334	
335	            agent.evtSource = evtSource;
336	        }
