338	        function setupControls(agentId) {
339	            const input = document.getElementById(`input-${agentId}`);
340	            const panel = document.getElementById(`panel-${agentId}`);
341	            const sendBtn = panel.querySelector('.btn-send');
342	            const ctrlcBtn = panel.querySelector('.btn-ctrl-c');
343	
344	            function doSend() {
345	                const text = input.value;
346	                if (text) {
347	                    fetch(`${API_BASE}/api/agents/${agentId}/input`, {
348	                        method: 'POST',
349	                        headers: { 'Content-Type': 'application/json' },
350	                        body: JSON.stringify({ text }),
351	                    });
352	                    input.value = '';
353	                }
354	                input.focus();
355	            }
356	
357	            sendBtn.addEventListener('click', doSend);
358	            input.addEventListener('keydown', (e) => {
359	                if (e.key === 'Enter') doSend();
360	            });
361	
362	            ctrlcBtn.addEventListener('click', () => {
363	                fetch(`${API_BASE}/api/agents/${agentId}/ctrl-c`, { method: 'POST' });
364	                input.focus();
365	            });
366	
367	            const restartBtn = panel.querySelector('.btn-restart');
368	            restartBtn.addEventListener('click', async () => {
369	                restartBtn.textContent = 'Restarting...';
370	                restartBtn.disabled = true;
371	                try {
372	                    const res = await fetch(`${API_BASE}/api/agents/${agentId}/restart`, { method: 'POST' });
373	                    if (res.ok) {
374	                        // Reconnect SSE after a brief delay.
375	                        const agent = agents.get(agentId);
376	                        if (agent && agent.evtSource) agent.evtSource.close();
377	                        agent.term.clear();
378	                        setTimeout(() => connectSSE(agentId), 1000);
379	                        restartBtn.textContent = 'Restarted';
380	                    } else {
381	                        restartBtn.textContent = 'Failed';
382	                    }
383	                } catch (_) {
384	                    restartBtn.textContent = 'Error';
385	                }
386	                setTimeout(() => { restartBtn.textContent = 'Restart'; restartBtn.disabled = false; }, 2000);
387	            });
388	        }
