390	        // Poll agent states every 2 seconds
391	        async function pollStates() {
392	            try {
393	                const res = await fetch(`${API_BASE}/api/agents`);
394	                if (!res.ok) return;
395	                const list = await res.json();
396	                for (const agent of list) {
397	                    const badge = document.getElementById(`badge-${agent.id}`);
