407	        async function pollAgentSagas(agentIds) {
408	            for (const id of agentIds) {
409	                try {
410	                    const res = await fetch(`${API_BASE}/api/agents/${id}/saga`);
411	                    if (!res.ok) continue;
412	                    const data = await res.json();
413	                    const badge = document.getElementById(`saga-badge-${id}`);
414	                    if (badge && data.saga) {
415	                        const current = data.steps.find(s => s.status === 'in-progress');
416	                        badge.textContent = current ? `Step ${current.number}: ${current.slug}` : '';
417	                    }
418	                } catch (_) {}
419	            }
420	        }
