422	        async function init() {
423	            const res = await fetch(`${API_BASE}/api/agents`);
424	            const agentList = await res.json();
425	
426	            const dashboard = document.getElementById('dashboard');
427	            const count = agentList.length;
428	            document.getElementById('agent-count').textContent = `${count} agent${count !== 1 ? 's' : ''}`;
429	
430	            // Choose grid columns based on agent count
431	            if (count <= 1) dashboard.className = 'dashboard cols-1';
432	            else if (count <= 2) dashboard.className = 'dashboard cols-2';
433	            else dashboard.className = 'dashboard cols-3';
434	
435	            for (const agent of agentList) {
436	                const panel = createAgentPanel(agent);
437	                dashboard.appendChild(panel);
438	
439	                const { term, fitAddon } = initTerminal(agent.id);
440	                agents.set(agent.id, { term, fitAddon, panel, evtSource: null });
441	
442	                connectSSE(agent.id);
443	                setupControls(agent.id);
444	            }
445	
446	            // Fetch per-agent saga step for badges
447	            pollAgentSagas(agentList.map(a => a.id));
448	
449	            // Handle resize
450	            const fitAll = () => agents.forEach(a => a.fitAddon.fit());
451	            window.addEventListener('resize', fitAll);
452	            new ResizeObserver(fitAll).observe(dashboard);
453	
454	            // Poll states
455	            setInterval(pollStates, 2000);
456	        }
