605	        function renderSaga(data) {
606	            const infoDiv = document.getElementById('saga-info');
607	            const stepsDiv = document.getElementById('saga-steps');
608	            const trajDiv = document.getElementById('saga-trajectories');
609	            const trajList = document.getElementById('saga-traj-list');
610	            const distillBtn = document.getElementById('saga-distill-btn');
611	
612	            if (!data.saga) {
613	                infoDiv.innerHTML = '';
614	                stepsDiv.innerHTML = '<div class="saga-none">No .agentrail/ saga found in this project.</div>';
615	                trajDiv.style.display = 'none';
616	                distillBtn.style.display = 'none';
617	                return;
618	            }
619	
620	            const saga = data.saga;
621	            const steps = data.steps;
622	            const completed = steps.filter(s => s.status === 'completed').length;
623	            const total = steps.length;
624	            const current = steps.find(s => s.status === 'in-progress');
625	
626	            infoDiv.innerHTML = `
627	                <div class="saga-stat"><div class="saga-stat-label">Saga</div><div class="saga-stat-value">${saga.name}</div></div>
628	                <div class="saga-stat"><div class="saga-stat-label">Status</div><div class="saga-stat-value">${saga.status}</div></div>
629	                <div class="saga-stat"><div class="saga-stat-label">Progress</div><div class="saga-stat-value">${completed} / ${total}</div></div>
630	                <div class="saga-stat"><div class="saga-stat-label">Current Step</div><div class="saga-stat-value">${current ? current.slug : 'none'}</div></div>
631	            `;
632	
633	            stepsDiv.innerHTML = '';
634	            for (const step of steps) {
635	                const statusCls = 'step-' + step.status.replace(/_/g, '-');
636	                const isCurrent = step.status === 'in-progress';
637	                const card = document.createElement('div');
638	                card.className = `step-card ${statusCls}` + (isCurrent ? ' step-current' : '');
639	                const desc = step.description.length > 120 ? step.description.slice(0, 120) + '...' : step.description;
640	                card.innerHTML = `
641	                    <div class="step-number">${step.number}</div>
642	                    <div class="step-body">
643	                        <div class="step-header">
644	                            <span class="step-slug">${step.slug}</span>
645	                            <span class="step-status">${step.status}</span>
646	                        </div>
647	                        <div class="step-desc">${desc}</div>
648	                        <div class="step-meta">
649	                            ${step.role ? `<span>Role: ${step.role}</span>` : ''}
650	                            ${step.task_type ? `<span>Task: ${step.task_type}</span>` : ''}
651	                            ${step.completed_at ? `<span>Done: ${step.completed_at}</span>` : ''}
652	                        </div>
653	                    </div>
654	                `;
655	                stepsDiv.appendChild(card);
656	            }
657	
658	            // Trajectories
659	            sagaCurrentTaskType = current && current.task_type ? current.task_type : null;
660	            if (data.trajectories.length > 0) {
661	                trajDiv.style.display = '';
662	                trajList.innerHTML = '';
663	                for (const t of data.trajectories) {
664	                    const rewardCls = t.reward > 0 ? 'traj-reward-pos' : (t.reward < 0 ? 'traj-reward-neg' : 'traj-reward-zero');
665	                    const tc = document.createElement('div');
666	                    tc.className = 'traj-card';
667	                    tc.innerHTML = `
668	                        <div class="traj-action">${t.action}</div>
669	                        <div class="traj-meta">
670	                            <span class="${rewardCls}">Reward: ${t.reward > 0 ? '+' : ''}${t.reward}</span>
671	                            &middot; ${t.result} &middot; ${t.timestamp}
672	                        </div>
673	                    `;
674	                    trajList.appendChild(tc);
675	                }
676	                distillBtn.style.display = sagaCurrentTaskType ? '' : 'none';
677	            } else {
678	                trajDiv.style.display = 'none';
679	                distillBtn.style.display = 'none';
680	            }
681	        }
682	
683	        async function sagaDistill() {
684	            if (!sagaCurrentTaskType) return;
685	            const btn = document.getElementById('saga-distill-btn');
686	            btn.textContent = 'Distilling...';
687	            btn.disabled = true;
688	            try {
689	                const res = await fetch(`${API_BASE}/api/saga/distill`, {
690	                    method: 'POST',
691	                    headers: { 'Content-Type': 'application/json' },
692	                    body: JSON.stringify({ task_type: sagaCurrentTaskType }),
693	                });
694	                const data = await res.json();
695	                if (data.exit_code === 0) {
696	                    btn.textContent = 'Distilled!';
697	                } else {
698	                    btn.textContent = 'Distill Failed';
699	                }
700	            } catch (_) {
701	                btn.textContent = 'Error';
702	            }
703	            setTimeout(() => { btn.textContent = 'Distill Skill'; btn.disabled = false; }, 3000);
704	        }
