706	        // ── Events log ────────────────────────────────────────
707	        let eventsLastIndex = 0;
708	
709	        const KIND_LABELS = {
710	            feature_request: 'Feature Request',
711	            bug_fix_request: 'Bug Fix',
712	            completion_notice: 'Completed',
713	            blocked_notice: 'Blocked',
714	            needs_info: 'Needs Info',
715	            verification_request: 'Verify',
716	        };
717	
718	        function kindLabel(kind) { return KIND_LABELS[kind] || kind; }
719	
720	        function decisionClass(decision) {
721	            if (decision.startsWith('deliver')) return 'decision-deliver';
722	            if (decision.startsWith('escalate')) return 'decision-escalate';
723	            return 'decision-broadcast';
