                const res = await fetch(`${API_BASE}/api/wiki/${encodeURIComponent(title)}`);
                if (!res.ok) return;
                const data = await res.json();
                wikiCurrentPage = title;
                wikiCurrentEtag = res.headers.get('ETag');

                document.getElementById('wiki-page-title').textContent = data.title;
                document.getElementById('wiki-content').innerHTML = data.html;
                document.getElementById('wiki-content').style.display = '';
                document.getElementById('wiki-edit-area').style.display = 'none';
                document.getElementById('wiki-edit-btn').style.display = '';
                document.getElementById('wiki-save-btn').style.display = 'none';
                document.getElementById('wiki-cancel-btn').style.display = 'none';
                document.getElementById('wiki-conflict').style.display = 'none';
                document.getElementById('wiki-editor').value = data.content;

                // Wire up wiki-link clicks
                document.querySelectorAll('#wiki-content a.wiki-link').forEach(a => {
                    a.addEventListener('click', (e) => {
                        e.preventDefault();
                        const target = a.getAttribute('data-wiki-link');
                        if (target) wikiOpenPage(target);
                    });
                });

                wikiLoadPageList();
            } catch (_) {}
        }

        function wikiToggleEdit() {
            wikiEditing = true;
            document.getElementById('wiki-content').style.display = 'none';
            document.getElementById('wiki-edit-area').style.display = 'flex';
            document.getElementById('wiki-edit-btn').style.display = 'none';
            document.getElementById('wiki-save-btn').style.display = '';
            document.getElementById('wiki-cancel-btn').style.display = '';
        }

        function wikiCancelEdit() {
            wikiEditing = false;
            document.getElementById('wiki-content').style.display = '';
            document.getElementById('wiki-edit-area').style.display = 'none';
            document.getElementById('wiki-edit-btn').style.display = '';
            document.getElementById('wiki-save-btn').style.display = 'none';
            document.getElementById('wiki-cancel-btn').style.display = 'none';
            document.getElementById('wiki-conflict').style.display = 'none';
        }

        async function wikiSave() {
            if (!wikiCurrentPage) return;
            const content = document.getElementById('wiki-editor').value;
            const headers = { 'Content-Type': 'application/json' };
            if (wikiCurrentEtag) headers['If-Match'] = wikiCurrentEtag;

            try {
                const res = await fetch(`${API_BASE}/api/wiki/${encodeURIComponent(wikiCurrentPage)}`, {
                    method: 'PUT',
                    headers,
                    body: JSON.stringify({ content }),
                });
                if (res.status === 409) {
                    const data = await res.json();
                    document.getElementById('wiki-conflict').textContent =
                        `Conflict: page was modified by another user. Current version shown below. Your edits are preserved in the editor.`;
                    document.getElementById('wiki-conflict').style.display = '';
                    wikiCurrentEtag = data.current_etag;
                    return;
                }
                if (res.ok) {
                    wikiCurrentEtag = res.headers.get('ETag');
                    wikiOpenPage(wikiCurrentPage);
                }
            } catch (_) {}
        }

        async function wikiNewPage() {
            const input = document.getElementById('wiki-new-title');
            const title = input.value.trim();
            if (!title) return;

            try {
                const res = await fetch(`${API_BASE}/api/wiki/${encodeURIComponent(title)}`, {
                    method: 'PUT',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ content: `# ${title}\n\n` }),
                });
                if (res.ok || res.status === 201) {
                    input.value = '';
                    wikiOpenPage(title);
                }
            } catch (_) {}
        }

        // ── Saga ──────────────────────────────────────────────
        let sagaCurrentTaskType = null;

        async function sagaRefresh() {
            try {
                const res = await fetch(`${API_BASE}/api/saga`);
                if (!res.ok) return;
                const data = await res.json();
                renderSaga(data);
            } catch (_) {}
        }

        function renderSaga(data) {
            const infoDiv = document.getElementById('saga-info');
            const stepsDiv = document.getElementById('saga-steps');
            const trajDiv = document.getElementById('saga-trajectories');
            const trajList = document.getElementById('saga-traj-list');
            const distillBtn = document.getElementById('saga-distill-btn');

            if (!data.saga) {
                infoDiv.innerHTML = '';
                stepsDiv.innerHTML = '<div class="saga-none">No .agentrail/ saga found in this project.</div>';
                trajDiv.style.display = 'none';
                distillBtn.style.display = 'none';
                return;
            }

            const saga = data.saga;
            const steps = data.steps;
            const completed = steps.filter(s => s.status === 'completed').length;
            const total = steps.length;
            const current = steps.find(s => s.status === 'in-progress');

            infoDiv.innerHTML = `
                <div class="saga-stat"><div class="saga-stat-label">Saga</div><div class="saga-stat-value">${saga.name}</div></div>
                <div class="saga-stat"><div class="saga-stat-label">Status</div><div class="saga-stat-value">${saga.status}</div></div>
                <div class="saga-stat"><div class="saga-stat-label">Progress</div><div class="saga-stat-value">${completed} / ${total}</div></div>
                <div class="saga-stat"><div class="saga-stat-label">Current Step</div><div class="saga-stat-value">${current ? current.slug : 'none'}</div></div>
            `;

            stepsDiv.innerHTML = '';
            for (const step of steps) {
                const statusCls = 'step-' + step.status.replace(/_/g, '-');
                const isCurrent = step.status === 'in-progress';
                const card = document.createElement('div');
                card.className = `step-card ${statusCls}` + (isCurrent ? ' step-current' : '');
                const desc = step.description.length > 120 ? step.description.slice(0, 120) + '...' : step.description;
                card.innerHTML = `
                    <div class="step-number">${step.number}</div>
                    <div class="step-body">
                        <div class="step-header">
                            <span class="step-slug">${step.slug}</span>
                            <span class="step-status">${step.status}</span>
                        </div>
                        <div class="step-desc">${desc}</div>
                        <div class="step-meta">
                            ${step.role ? `<span>Role: ${step.role}</span>` : ''}
                            ${step.task_type ? `<span>Task: ${step.task_type}</span>` : ''}
                            ${step.completed_at ? `<span>Done: ${step.completed_at}</span>` : ''}
                        </div>
                    </div>
                `;
                stepsDiv.appendChild(card);
            }

            // Trajectories
            sagaCurrentTaskType = current && current.task_type ? current.task_type : null;
            if (data.trajectories.length > 0) {
                trajDiv.style.display = '';
                trajList.innerHTML = '';
                for (const t of data.trajectories) {
                    const rewardCls = t.reward > 0 ? 'traj-reward-pos' : (t.reward < 0 ? 'traj-reward-neg' : 'traj-reward-zero');
                    const tc = document.createElement('div');
                    tc.className = 'traj-card';
                    tc.innerHTML = `
                        <div class="traj-action">${t.action}</div>
                        <div class="traj-meta">
                            <span class="${rewardCls}">Reward: ${t.reward > 0 ? '+' : ''}${t.reward}</span>
                            &middot; ${t.result} &middot; ${t.timestamp}
                        </div>
                    `;
                    trajList.appendChild(tc);
                }
                distillBtn.style.display = sagaCurrentTaskType ? '' : 'none';
            } else {
                trajDiv.style.display = 'none';
                distillBtn.style.display = 'none';
            }
        }

        async function sagaDistill() {
            if (!sagaCurrentTaskType) return;
            const btn = document.getElementById('saga-distill-btn');
            btn.textContent = 'Distilling...';
            btn.disabled = true;
            try {
                const res = await fetch(`${API_BASE}/api/saga/distill`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ task_type: sagaCurrentTaskType }),
                });
                const data = await res.json();
                if (data.exit_code === 0) {
                    btn.textContent = 'Distilled!';
                } else {
                    btn.textContent = 'Distill Failed';
                }
            } catch (_) {
                btn.textContent = 'Error';
            }
            setTimeout(() => { btn.textContent = 'Distill Skill'; btn.disabled = false; }, 3000);
        }

        // ── Events log ────────────────────────────────────────
        let eventsLastIndex = 0;

        const KIND_LABELS = {
            feature_request: 'Feature Request',
            bug_fix_request: 'Bug Fix',
            completion_notice: 'Completed',
            blocked_notice: 'Blocked',
            needs_info: 'Needs Info',
            verification_request: 'Verify',
        };

        function kindLabel(kind) { return KIND_LABELS[kind] || kind; }

        function decisionClass(decision) {
            if (decision.startsWith('deliver')) return 'decision-deliver';
            if (decision.startsWith('escalate')) return 'decision-escalate';
            return 'decision-broadcast';
        }

        function decisionLabel(decision) {
            if (decision.startsWith('deliver:')) return 'Delivered to ' + decision.slice(8);
            if (decision.startsWith('escalate:')) return 'Escalated: ' + decision.slice(9);
            return 'Broadcast';
        }

        async function eventsRefresh() {
            try {
                const res = await fetch(`${API_BASE}/api/events?since=0`);
                if (!res.ok) return;
                const entries = await res.json();
                const list = document.getElementById('events-list');
                const escDiv = document.getElementById('events-escalations');
                list.innerHTML = '';
                escDiv.innerHTML = '';

                // Show escalations at the top
                const escalations = entries.filter(e => e.decision.startsWith('escalate'));
                for (const esc of escalations) {
                    const banner = document.createElement('div');
                    banner.className = 'escalation-banner';
                    banner.innerHTML = `<span class="esc-icon">!</span>
                        <span><strong>Human attention needed:</strong> ${esc.event.summary}
                        (from ${esc.event.source_agent}, target: ${esc.event.target_agent || 'none'}) &mdash; ${esc.decision.slice(9)}</span>`;
                    escDiv.appendChild(banner);
                }

                // Show all events newest-first
                for (let i = entries.length - 1; i >= 0; i--) {
                    const entry = entries[i];
                    const ev = entry.event;
                    const card = document.createElement('div');
                    card.className = 'event-card';
                    card.innerHTML = `
                        <div class="event-header">
                            <span class="event-kind kind-${ev.kind}">${kindLabel(ev.kind)}</span>
                            <span class="event-decision ${decisionClass(entry.decision)}">${decisionLabel(entry.decision)}</span>
                        </div>
                        <div class="event-summary">${ev.summary}</div>
                        <div class="event-meta">
                            <span>From: ${ev.source_agent}</span>
                            <span>Target: ${ev.target_agent || '(broadcast)'}</span>
                            <span>Priority: ${ev.priority}</span>
                            <span>${entry.logged_at}</span>
                        </div>`;
                    list.appendChild(card);
                }
                eventsLastIndex = entries.length;
            } catch (_) {}
        }

        // Poll events every 5 seconds for new escalations (shown as badge on tab)
        let eventsPollCount = 0;
        setInterval(async () => {
            try {
                const res = await fetch(`${API_BASE}/api/events?since=${eventsLastIndex}`);
                if (!res.ok) return;
                const entries = await res.json();
                if (entries.length > 0) {
                    eventsPollCount += entries.length;
                    eventsLastIndex += entries.length;
                    const tab = document.getElementById('tab-events');
                    const hasEscalation = entries.some(e => e.decision.startsWith('escalate'));
                    if (hasEscalation) {
                        tab.style.borderColor = '#e94560';
                        tab.style.color = '#e94560';
                        playNotification();
                    }
                    // If events view is active, refresh it
                    if (document.getElementById('events-view').style.display !== 'none') {
                        eventsRefresh();
                    }
                }
            } catch (_) {}
        }, 5000);

        // ── Dependency graph ─────────────────────────────────
        const STATE_COLORS = {
            starting: '#9ca3af', running: '#34d399', idle: '#60a5fa',
            awaiting_human_input: '#fbbf24', busy: '#a78bfa', blocked: '#fca5a5',
            completed_task: '#6ee7b7', error: '#f87171', disconnected: '#6b7280',
        };
        const STATE_BG = {
            starting: '#1f2937', running: '#064e3b', idle: '#1e3a5f',
            awaiting_human_input: '#78350f', busy: '#4c1d95', blocked: '#7f1d1d',
            completed_task: '#064e3b', error: '#7f1d1d', disconnected: '#1f2937',
        };

        async function graphRefresh() {
            try {
                const res = await fetch(`${API_BASE}/api/agents/graph`);
                if (!res.ok) return;
                const nodes = await res.json();
                renderGraph(nodes);
            } catch (_) {}
        }

        function renderGraph(nodes) {
            const canvas = document.getElementById('graph-canvas');
            if (nodes.length === 0) {
                canvas.innerHTML = '<div style="color:#666;font-size:14px;">No agents running.</div>';
                return;
            }

            const nodeW = 180, nodeH = 50, padX = 60, padY = 40;
            const cols = Math.min(nodes.length, 4);
            const rows = Math.ceil(nodes.length / cols);
            const svgW = cols * (nodeW + padX) + padX;
            const svgH = rows * (nodeH + padY) + padY;

            // Assign positions
            const positions = {};
            nodes.forEach((n, i) => {
                const col = i % cols;
                const row = Math.floor(i / cols);
                positions[n.id] = {
                    x: padX + col * (nodeW + padX),
                    y: padY + row * (nodeH + padY),
                };
            });

            let svg = `<svg class="graph-svg" viewBox="0 0 ${svgW} ${svgH}" xmlns="http://www.w3.org/2000/svg">`;
            svg += `<defs><marker id="arrowhead" markerWidth="10" markerHeight="7" refX="10" refY="3.5" orient="auto"><polygon points="0 0, 10 3.5, 0 7" fill="#e94560" /></marker></defs>`;

            // Draw edges (blocked_on -> blocker)
            for (const node of nodes) {
                const to = positions[node.id];
                if (!to) continue;
                for (const dep of node.blocked_on) {
                    const from = positions[dep];
                    if (!from) continue;
                    svg += `<line class="graph-edge" x1="${from.x + nodeW / 2}" y1="${from.y + nodeH}" x2="${to.x + nodeW / 2}" y2="${to.y}" />`;
                }
            }

            // Draw nodes
            for (const node of nodes) {
                const pos = positions[node.id];
                const color = STATE_COLORS[node.state] || '#888';
                const bg = STATE_BG[node.state] || '#16213e';
                svg += `<g class="graph-node">`;
                svg += `<rect x="${pos.x}" y="${pos.y}" width="${nodeW}" height="${nodeH}" fill="${bg}" stroke="${color}" />`;
                svg += `<text x="${pos.x + nodeW / 2}" y="${pos.y + 20}" text-anchor="middle" font-weight="600">${node.name}</text>`;
                svg += `<text x="${pos.x + nodeW / 2}" y="${pos.y + 38}" text-anchor="middle" font-size="11" fill="${color}">${stateLabel({state: node.state})}</text>`;
                svg += `</g>`;
            }

            svg += `</svg>`;
            canvas.innerHTML = svg;
        }

        // ── Notification sounds ──────────────────────────────
        // Use Web Audio API to generate a short attention tone (no external files needed).
        let audioCtx = null;
        let notificationsEnabled = true;
        const prevAgentStates = new Map();

        function playNotification() {
            if (!notificationsEnabled) return;
            try {
                if (!audioCtx) audioCtx = new (window.AudioContext || window.webkitAudioContext)();
                const osc = audioCtx.createOscillator();
                const gain = audioCtx.createGain();
                osc.connect(gain);
                gain.connect(audioCtx.destination);
                osc.type = 'sine';
                osc.frequency.setValueAtTime(880, audioCtx.currentTime);
                osc.frequency.setValueAtTime(660, audioCtx.currentTime + 0.1);
                gain.gain.setValueAtTime(0.3, audioCtx.currentTime);
                gain.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.3);
                osc.start(audioCtx.currentTime);
                osc.stop(audioCtx.currentTime + 0.3);
            } catch (_) {}
        }

        // Check for state changes that need attention during polling.
        const origPollStates = pollStates;
        pollStates = async function() {
            try {
                const res = await fetch(`${API_BASE}/api/agents`);
                if (!res.ok) return;
                const list = await res.json();
                for (const agent of list) {
                    const sk = stateKey(agent.state);
                    const badge = document.getElementById(`badge-${agent.id}`);
                    if (badge) {
                        badge.className = `state-badge state-${sk}`;
                        badge.textContent = stateLabel(agent.state);
                    }
                    // Play notification on attention-needing state transitions.
                    const prev = prevAgentStates.get(agent.id);
                    if (prev && prev !== sk && (sk === 'awaiting_human_input' || sk === 'error' || sk === 'blocked')) {
                        playNotification();
                    }
                    prevAgentStates.set(agent.id, sk);
                }
            } catch (_) {}
        };
    </script>
</body>
</html>

