    /// Base directory for resolving relative paths.
    base_dir: PathBuf,
    /// Path to agents.toml for saving config.
    config_path: PathBuf,
}

type AppState = SharedState;

static INDEX_HTML: &str = include_str!("../static/index.html");

const DEFAULT_CONFIG_PATH: &str = "agents.toml";

#[derive(Deserialize)]
struct InputPayload {
    text: String,
}

#[derive(Serialize)]
struct AgentInfo {
    id: String,
    name: String,
    role: String,
