// ── Agent lifecycle controls ──────────────────────

function toggleNewAgent() {
    const bar = document.getElementById('new-agent-bar');
    bar.classList.toggle('visible');
}

async function createAgent() {
    const id = document.getElementById('new-id').value.trim();
    const name = document.getElementById('new-name').value.trim();
    const repoPath = document.getElementById('new-path').value.trim();
    const role = document.getElementById('new-role').value;
    const launch = document.getElementById('new-launch').value.trim();

    if (!id || !name) { alert('Agent ID and Name are required.'); return; }

    const body = {
        id, name,
        repo_path: repoPath || '.',
        role,
        launch_command: launch || 'bash',
    };

    try {
        const res = await fetch(`${API_BASE}/api/agents`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
        });
        if (res.ok || res.status === 201) {
            // Clear form and hide bar.
            document.getElementById('new-id').value = '';
            document.getElementById('new-name').value = '';
            document.getElementById('new-path').value = '';
            document.getElementById('new-launch').value = 'bash';
            document.getElementById('new-agent-bar').classList.remove('visible');
            // Add the new panel.
            addAgentPanel({ id, name, role, state: { state: 'starting' } });
        } else {
            const text = await res.text();
            alert(`Failed to create agent: ${text}`);
        }
    } catch (e) {
        alert(`Error creating agent: ${e}`);
    }
}

function addAgentPanel(agent) {
    const dashboard = document.getElementById('dashboard');
    const panel = createAgentPanel(agent);
    dashboard.appendChild(panel);

    const { term, fitAddon } = initTerminal(agent.id);
    agents.set(agent.id, { term, fitAddon, panel, evtSource: null });
    connectSSE(agent.id);
    setupControls(agent.id);
    refreshDashboardLayout();
}

function refreshDashboardLayout() {
    const dashboard = document.getElementById('dashboard');
    const count = dashboard.querySelectorAll('.agent-panel').length;
    document.getElementById('agent-count').textContent = `${count} agent${count !== 1 ? 's' : ''}`;
    if (count <= 1) dashboard.className = 'dashboard cols-1';
    else if (count <= 2) dashboard.className = 'dashboard cols-2';
    else dashboard.className = 'dashboard cols-3';
    agents.forEach(a => a.fitAddon.fit());
}

function toggleConfig(agentId) {
    const editor = document.getElementById(`cfg-${agentId}`);
    editor.classList.toggle('visible');
}

async function applyConfig(agentId) {
    const name = document.getElementById(`cfg-name-${agentId}`).value.trim();
    const repoPath = document.getElementById(`cfg-path-${agentId}`).value.trim();
    const role = document.getElementById(`cfg-role-${agentId}`).value;
    const launch = document.getElementById(`cfg-launch-${agentId}`).value.trim();

    const body = {};
    if (name) body.name = name;
    if (repoPath) body.repo_path = repoPath;
    if (role) body.role = role;
    if (launch) body.launch_command = launch;

    try {
        const res = await fetch(`${API_BASE}/api/agents/${agentId}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
        });
        if (res.ok) {
            toggleConfig(agentId);
            // Reconnect SSE after restart.
            const agent = agents.get(agentId);
            if (agent && agent.evtSource) agent.evtSource.close();
            agent.term.clear();
            setTimeout(() => connectSSE(agentId), 1000);
            // Update header display.
            const panel = document.getElementById(`panel-${agentId}`);
            if (name) panel.querySelector('.agent-name').textContent = name;
            if (role) panel.querySelector('.agent-role').textContent = role;
        } else {
            alert('Failed to update agent config.');
        }
    } catch (e) {
        alert(`Error updating config: ${e}`);
    }
}

async function saveToToml() {
    const btn = document.getElementById('btn-save-toml');
    btn.textContent = 'Saving...';
    btn.disabled = true;
    try {
        const res = await fetch(`${API_BASE}/api/agents/save`, { method: 'POST' });
        if (res.ok) {
            btn.textContent = 'Saved!';
        } else {
            const text = await res.text();
            btn.textContent = 'Failed';
            console.error('Save failed:', text);
        }
    } catch (_) {
        btn.textContent = 'Error';
    }
    setTimeout(() => { btn.textContent = 'Save'; btn.disabled = false; }, 2000);
}

