        alert(`Error updating config: ${e}`);
    }
}

async function saveToToml() {
    const btn = document.getElementById('btn-save-toml');
    btn.textContent = 'Saving...';
    btn.disabled = true;
    try {
        const res = await fetch(`${API_BASE}/api/agents/save`, { method: 'POST' });
        if (res.ok) {
            btn.textContent = 'Saved!';
        } else {
            const text = await res.text();
            btn.textContent = 'Failed';
            console.error('Save failed:', text);
        }
    } catch (_) {
        btn.textContent = 'Error';
    }
    setTimeout(() => { btn.textContent = 'Save'; btn.disabled = false; }, 2000);
}

